export enum MembershipStatus {
  INACTIVE = 'INACTIVE',
  PENDING = 'PENDING',
  ACTIVE = 'ACTIVE'
}

export enum SocialPlatform {
  INSTAGRAM = 'Instagram',
  TIKTOK = 'TikTok',
  TWITTER = 'Twitter',
  YOUTUBE = 'YouTube'
}

export interface UserProfile {
  id: string;
  name: string;
  username: string;
  avatar: string;
  handles: Record<SocialPlatform, string>;
  membershipStatus: MembershipStatus;
  joinedAt: string;
  followingCount: number;
  followersCount: number;
}

export interface CampaignTask {
  id: string;
  creatorId: string;
  creatorName: string;
  platform: SocialPlatform;
  actionType: 'Like' | 'Follow' | 'Comment' | 'Share' | 'Stream' | 'View';
  link: string;
  points: number;
  remainingSlots: number;
  totalSlots: number;
  description: string;
}

export interface Achievement {
  id: string;
