import React from 'react';
import { ExternalLink, Heart, Eye, MessageCircle, Share2, Youtube, Instagram, Twitter, Music2 } from 'lucide-react';
import { CampaignTask, SocialPlatform } from '../types';

interface CampaignCardProps {
  task: CampaignTask;
  onAction: (id: string) => void;
}

const CampaignCard: React.FC<CampaignCardProps> = ({ task, onAction }) => {
  const getPlatformIcon = (platform: SocialPlatform) => {
    switch (platform) {
      case SocialPlatform.INSTAGRAM: return <Instagram size={18} className="text-pink-500" />;
      case SocialPlatform.TIKTOK: return <Music2 size={18} className="text-cyan-400" />;
      case SocialPlatform.TWITTER: return <Twitter size={18} className="text-blue-400" />;
      case SocialPlatform.YOUTUBE: return <Youtube size={18} className="text-red-500" />;
      default: return null;
    }
  };

  const getActionIcon = (type: string) => {
    switch (type) {
      case 'Like': return <Heart size={16} />;
      case 'View': return <Eye size={16} />;
      case 'Comment': return <MessageCircle size={16} />;
      case 'Share': return <Share2 size={16} />;
      default: return <Heart size={16} />;
    }
  };

  const progress = (1 - (task.remainingSlots / task.totalSlots)) * 100;

  return (
    <div className="bg-slate-900/50 border border-slate-800 p-5 rounded-2xl hover:border-slate-700 transition-all group">
      <div className="flex justify-between items-start mb-4">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 rounded-full bg-slate-800 flex items-center justify-center border border-slate-700">
            {getPlatformIcon(task.platform)}
          </div>
          <div>
            <h4 className="text-sm font-semibold">{task.creatorName}</h4>
            <span className="text-xs text-slate-500">{task.platform} • {task.actionType}</span>
          </div>
        </div>
        <div className="bg-indigo-500/10 text-indigo-400 text-xs font-bold px-2 py-1 rounded">
          +{task.points} PTS
        </div>
      </div>

      <p className="text-sm text-slate-400 mb-4 line-clamp-2">
        {task.description}
      </p>

      <div className="space-y-3 mb-5">
        <div className="flex justify-between text-xs text-slate-500">
          <span>Community Progress</span>
          <span>{task.totalSlots - task.remainingSlots} / {task.totalSlots}</span>
        </div>
        <div className="h-1.5 w-full bg-slate-800 rounded-full overflow-hidden">
          <div 
            className="h-full bg-indigo-500 rounded-full transition-all duration-500"
            style={{ width: `${progress}%` }}
          />
        </div>
      </div>

      <div className="flex gap-2">
        <a 
          href={task.link} 
          target="_blank" 
          rel="noopener noreferrer"
          className="flex-1 flex items-center justify-center gap-2 bg-slate-800 hover:bg-slate-700 text-slate-200 py-2.5 rounded-xl text-sm font-medium transition-colors"
        >
          <ExternalLink size={16} />
          View Post
        </a>
        <button 
          onClick={() => onAction(task.id)}
          className="flex-1 flex items-center justify-center gap-2 bg-indigo-600 hover:bg-indigo-500 text-white py-2.5 rounded-xl text-sm font-medium transition-colors"
        >
          {getActionIcon(task.actionType)}
          Complete
        </button>
      </div>
    </div>
  );
};

export default CampaignCard;

