                        className="flex items-center gap-2 bg-slate-900 hover:bg-slate-800 text-indigo-400 px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest border border-slate-800 hover:border-indigo-500/30 transition-all"
                      >
                        Follow
                        <ExternalLink size={12} />
                      </a>
                    </div>
                  ))}
                </div>
                <div className="mt-4 p-3 bg-emerald-500/5 rounded-2xl border border-emerald-500/10">
                   <p className="text-[10px] text-emerald-400 font-medium leading-relaxed">
                     <span className="font-black uppercase mr-1">Magix Pact:</span> 
                     {member.name.split(' ')[0]} will be notified and bound to reciprocate within 24 hours.
                   </p>
                </div>
              </div>
            )}
          </div>
        )) : (
          <div className="col-span-full py-20 text-center glass rounded-[2.5rem] border-dashed border-slate-800">
             <div className="w-16 h-16 bg-slate-900 rounded-3xl flex items-center justify-center mx-auto mb-4">
                <Filter size={32} className="text-slate-600" />
             </div>
             <p className="text-slate-500 font-bold">No members found matching your specific interests.</p>
             <button 
              onClick={() => setFilterMode('all')}
              className="mt-4 text-indigo-400 text-xs font-black uppercase tracking-widest hover:underline"
             >
               Show All Members
             </button>
          </div>
        )}
      </div>
    </div>
  );
};

