                    <p className={`text-sm font-black ${syncStep >= 2 ? 'text-white' : 'text-slate-500'}`}>You → Community</p>
                    <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">Reciprocal Pact Fulfillment</p>
