             onClick={() => setFilterMode('all')}
             className={`px-6 py-2 rounded-xl text-[10px] font-black uppercase transition-all ${filterMode === 'all' ? 'bg-slate-800 text-white shadow-lg' : 'text-slate-500 hover:text-slate-300'}`}
