                    <RefreshCcw size={20} className={syncStep === 1 ? "animate-spin" : ""} />
                  </div>
                  <div className="text-left">
                    <p className={`text-sm font-black ${syncStep >= 2 ? 'text-white' : 'text-slate-500'}`}>You → Community</p>
                    <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">Reciprocal Pact Fulfillment</p>
                  </div>
                </div>
                {syncStep >= 2 && <CheckCircle size={20} className="text-emerald-500 animate-in zoom-in" />}
              </div>
            </div>

            <p className="text-[10px] font-black text-slate-600 uppercase tracking-[0.2em]">Magix Engine: Syncing Handles...</p>
          </div>
        </div>
      )}

      <Layout activeView={activeView} setActiveView={setActiveView} user={user}>
        {renderView()}
      </Layout>
    </div>
  );
};

