                    <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">Entering Follow-Back Loop</p>
                  </div>
                </div>
                {syncStep >= 1 && <CheckCircle size={20} className="text-emerald-500 animate-in zoom-in" />}
              </div>

              <div className={`flex items-center justify-between p-5 rounded-3xl border transition-all duration-700 ${syncStep >= 2 ? 'bg-purple-500/10 border-purple-500/30' : 'bg-slate-900/50 border-slate-800'}`}>
                <div className="flex items-center gap-4">
                  <div className={`w-10 h-10 rounded-xl flex items-center justify-center ${syncStep >= 2 ? 'bg-purple-500 text-white shadow-lg' : 'bg-slate-800 text-slate-500'}`}>
                    <RefreshCcw size={20} className={syncStep === 1 ? "animate-spin" : ""} />
                  </div>
                  <div className="text-left">
                    <p className={`text-sm font-black ${syncStep >= 2 ? 'text-white' : 'text-slate-500'}`}>Elite Verification</p>
                    <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">Badge Distribution Active</p>
                  </div>
                </div>
                {syncStep >= 2 && <CheckCircle size={20} className="text-emerald-500 animate-in zoom-in" />}
              </div>
            </div>

            <p className="text-[10px] font-black text-slate-600 uppercase tracking-[0.2em]">Wetaract Engine: Initializing Ecosystem...</p>
          </div>
        </div>
      )}

      <Layout activeView={activeView} setActiveView={setActiveView} user={user}>
        {renderView()}
      </Layout>
    </div>
  );
};

