                        { id: SocialPlatform.FACEBOOK, icon: Facebook, color: 'hover:text-blue-600' },
                        { id: SocialPlatform.TIKTOK, icon: Music2, color: 'hover:text-cyan-400' },
                        { id: SocialPlatform.YOUTUBE, icon: Youtube, color: 'hover:text-red-500' },
                        { id: SocialPlatform.TWITTER, icon: Twitter, color: 'hover:text-blue-400' },
                        { id: SocialPlatform.SPOTIFY, icon: Play, color: 'hover:text-emerald-500' },
                      ].map((p) => (
                        <button
                          key={p.id}
                          type="button"
                          onClick={() => setNewCampaign({ ...newCampaign, platform: p.id })}
                          className={`flex flex-col items-center justify-center p-4 rounded-2xl border transition-all ${
                            newCampaign.platform === p.id 
                              ? (newCampaign.isPaid ? 'bg-emerald-600 border-emerald-500 text-white shadow-xl' : 'bg-indigo-600 border-indigo-500 text-white shadow-xl')
                              : 'bg-slate-900 border-slate-800 text-slate-500 ' + p.color
                          }`}
                        >
                          <p.icon size={24} fill={p.id === SocialPlatform.SPOTIFY && newCampaign.platform === p.id ? "white" : "none"} />
                        </button>
                      ))}
                    </div>
                  </div>

                  {/* Link & Details */}
                  <div className="space-y-4">
                    <label className="block text-[10px] font-black text-slate-500 uppercase tracking-widest mb-2 ml-1">2. Target Content & CTA</label>
                    <div className="relative group">
                      <LinkIcon className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-500 group-focus-within:text-indigo-400" size={18} />
                      <input 
                        type="url" 
                        placeholder="Paste your content link (e.g. TikTok video, YouTube stream)" 
                        className="w-full bg-slate-950 border border-slate-800 rounded-2xl py-4 pl-12 pr-4 outline-none focus:border-indigo-500/50 text-white text-sm"
                        required
                        value={newCampaign.link}
                        onChange={(e) => setNewCampaign({ ...newCampaign, link: e.target.value })}
                      />
                    </div>
                    <div className="relative group">
                      <MessageSquare className="absolute left-4 top-4 text-slate-500 group-focus-within:text-indigo-400" size={18} />
                      <textarea 
                        placeholder="Campaign message - describe the action required (e.g. 'View for 3 mins', 'Repost to your wall')..." 
                        className="w-full bg-slate-950 border border-slate-800 rounded-2xl py-4 pl-12 pr-4 outline-none focus:border-indigo-500/50 text-white text-sm min-h-[100px]"
                        value={newCampaign.description}
                        onChange={(e) => setNewCampaign({ ...newCampaign, description: e.target.value })}
                      />
                    </div>
                  </div>

                  {newCampaign.isPaid ? (
                    <div className="space-y-6 animate-in slide-in-from-top-4 duration-300">
                      <div className="grid grid-cols-2 gap-4">
                        <div>
                          <label className="block text-[10px] font-black text-slate-500 uppercase tracking-widest mb-2 ml-1 flex items-center gap-2">
                             <Coins size={14} className="text-emerald-400" />
                             Campaign Budget ($)
                          </label>
                          <input 
                            type="number" 
                            min="5"
                            className="w-full bg-slate-950 border border-slate-800 rounded-2xl p-4 outline-none focus:border-emerald-500/50 text-white text-sm font-bold"
                            value={newCampaign.budget}
                            onChange={(e) => setNewCampaign({ ...newCampaign, budget: Number(e.target.value) })}
                          />
                        </div>
                        <div>
                          <label className="block text-[10px] font-black text-slate-500 uppercase tracking-widest mb-2 ml-1 flex items-center gap-2">
                             <Globe size={14} className="text-emerald-400" />
                             Geo Location Target
                          </label>
                          <select 
                            className="w-full bg-slate-950 border border-slate-800 rounded-2xl p-4 outline-none focus:border-emerald-500/50 text-white text-sm"
                            value={newCampaign.targetLocation}
                            onChange={(e) => setNewCampaign({ ...newCampaign, targetLocation: e.target.value })}
                          >
                            <option value="Global">Worldwide Reach</option>
                            <option value="USA">United States</option>
                            <option value="Nigeria">Nigeria</option>
                            <option value="UK">United Kingdom</option>
                            <option value="Europe">European Union</option>
                            <option value="Africa">Pan-African</option>
                          </select>
                        </div>
                      </div>

                      <div className={`p-6 rounded-[2rem] border transition-all cursor-pointer ${newCampaign.useAI ? 'bg-emerald-500/10 border-emerald-500/30 shadow-[0_0_30px_rgba(16,185,129,0.1)]' : 'bg-slate-900 border-slate-800'}`} onClick={() => setNewCampaign({ ...newCampaign, useAI: !newCampaign.useAI })}>
                         <div className="flex items-center justify-between">
                            <div className="flex items-center gap-4">
                               <div className={`p-3 rounded-xl ${newCampaign.useAI ? 'bg-emerald-500 text-white' : 'bg-slate-800 text-slate-500'}`}>
                                  <Cpu size={20} />
                               </div>
                               <div>
                                  <h4 className="font-black text-sm text-white uppercase tracking-tight">AI Smart Advertiser</h4>
                                  <p className="text-[10px] text-slate-500 font-medium">Auto-distribute to viral niches for max conversion.</p>
                               </div>
                            </div>
                            <div className={`w-12 h-6 rounded-full relative transition-all ${newCampaign.useAI ? 'bg-emerald-500' : 'bg-slate-700'}`}>
                               <div className={`absolute top-1 w-4 h-4 bg-white rounded-full transition-all ${newCampaign.useAI ? 'right-1' : 'left-1'}`}></div>
                            </div>
                         </div>
                      </div>
                    </div>
                  ) : (
                    <div>
                      <label className="block text-[10px] font-black text-slate-500 uppercase tracking-widest mb-2 ml-1 flex items-center gap-2">
                         <Target size={14} className="text-indigo-400" />
                         Target Community Niche
                      </label>
                      <select 
                        className="w-full bg-slate-950 border border-slate-800 rounded-2xl p-4 outline-none focus:border-indigo-500/50 text-white text-sm"
                        value={newCampaign.targetInterest}
                        onChange={(e) => setNewCampaign({ ...newCampaign, targetInterest: e.target.value })}
                      >
                        <option value="">All Community Members</option>
                        {user.interests.map(i => (
                          <option key={i} value={i}>Members interested in: {i}</option>
                        ))}
                      </select>
                    </div>
                  )}
                </div>

                <div className="pt-4">
                  <button type="submit" className={`w-full text-white font-black py-5 rounded-[2rem] transition-all shadow-xl active:scale-95 text-lg ${newCampaign.isPaid ? 'bg-emerald-600 hover:bg-emerald-500 shadow-emerald-600/20' : 'bg-indigo-600 hover:bg-indigo-500 shadow-indigo-600/20'}`}>
                    {newCampaign.isPaid ? 'Proceed to Secure Payment' : 'Launch Community Pact'}
                  </button>
                </div>
              </form>

              {/* Summary Card */}
              <div className="lg:col-span-1 space-y-6">
                <div className="glass p-8 rounded-[2.5rem] border-slate-800/50 sticky top-8">
                  <h3 className="text-lg font-bold text-white mb-6">Campaign Summary</h3>
                  <div className="space-y-4">
                    <div className="flex justify-between items-center py-3 border-b border-slate-800/50">
                       <span className="text-xs text-slate-500 font-bold uppercase">{newCampaign.isPaid ? 'Ad Budget' : 'Base Cost'}</span>
                       <span className="text-sm text-white font-black">{newCampaign.isPaid ? `$${newCampaign.budget.toFixed(2)}` : '250 Pts'}</span>
                    </div>
                    {newCampaign.isPaid && (
                      <>
                        <div className="flex justify-between items-center py-3 border-b border-slate-800/50">
                          <div className="flex items-center gap-2">
                            <span className="text-xs text-slate-500 font-bold uppercase">Wetaract Fee (10%)</span>
                            <div className="group relative">
                               <Info size={12} className="text-slate-600" />
                               <div className="absolute bottom-full left-1/2 -translate-x-1/2 mb-2 w-48 p-2 bg-slate-900 text-[9px] rounded-lg opacity-0 group-hover:opacity-100 transition-opacity border border-slate-800 pointer-events-none z-20">
                                 Platform maintenance and AI Advertiser fee.
                               </div>
                            </div>
                          </div>
                          <span className="text-sm text-rose-400 font-black">-${platformFee.toFixed(2)}</span>
                        </div>
                        <div className="flex justify-between items-center py-3 border-b border-slate-800/50">
                          <span className="text-xs text-slate-500 font-bold uppercase">Subscribers Pool</span>
                          <span className="text-sm text-emerald-400 font-black">${rewardBudget.toFixed(2)}</span>
                        </div>
                      </>
                    )}
                    <div className="flex justify-between items-center py-3 border-b border-slate-800/50">
                       <span className="text-xs text-slate-500 font-bold uppercase">Estimated Reach</span>
                       <span className="text-sm text-white font-black">{newCampaign.isPaid ? (newCampaign.budget * 50).toLocaleString() + '+' : '50 Pacts'}</span>
                    </div>
                    <div className="pt-6">
                       <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-1">Total Impact Value</p>
                       <div className="flex items-center gap-2">
                          {newCampaign.isPaid ? <Coins size={20} className="text-emerald-400" /> : <Zap size={20} className="text-amber-400 fill-amber-400" />}
                          <span className="text-3xl font-black text-white">{newCampaign.isPaid ? `$${newCampaign.budget.toFixed(2)}` : '375 Pts'}</span>
                       </div>
                    </div>
                  </div>

                  <div className={`mt-8 p-4 rounded-2xl border ${newCampaign.isPaid ? 'bg-emerald-500/5 border-emerald-500/10' : 'bg-indigo-500/5 border-indigo-500/10'}`}>
                     <div className={`flex items-center gap-2 mb-2 ${newCampaign.isPaid ? 'text-emerald-400' : 'text-indigo-400'}`}>
                        <CheckCircle size={14} />
                        <span className="text-[10px] font-black uppercase tracking-widest">Escrow Guaranteed</span>
                     </div>
                     <p className="text-[10px] text-slate-500 leading-relaxed font-medium">
                        Funds are held in Wetaract Escrow. We only release payments to subscribers once our AI verify engine confirms the action is complete.
                     </p>
                  </div>
                </div>
              </div>
            </div>
          </div>
        );
      default:
        return <Dashboard user={user} />;
    }
  };

  if (!isAuthenticated) {
    return <Auth onLoginSuccess={() => setIsAuthenticated(true)} />;
  }

  return (
    <div className="relative min-h-screen bg-slate-950">
      {isSyncing && (
        <div className="fixed inset-0 z-[100] bg-slate-950/95 backdrop-blur-xl flex items-center justify-center p-6">
          <div className="max-w-lg w-full glass p-10 rounded-[3rem] text-center space-y-8 animate-in zoom-in duration-500 border-indigo-500/30 shadow-[0_0_100px_rgba(99,102,241,0.1)]">
            <div className="relative w-32 h-32 mx-auto mb-8">
              <div className="absolute inset-0 bg-indigo-500/20 rounded-full animate-ping"></div>
              <div className="relative z-10 w-full h-full bg-indigo-600 rounded-[2.5rem] flex items-center justify-center neo-shadow rotate-12 transition-transform hover:rotate-0">
                <ArrowLeftRight size={48} className="text-white" />
              </div>
            </div>

            <div className="space-y-4">
              <h2 className="text-4xl font-black text-white tracking-tight">Activating Founding Pact</h2>
              <p className="text-slate-400 font-medium leading-relaxed px-4">
                Synchronizing your profile with the Wetaract growth engine. You are now officially a part of the Founding Member circle.
              </p>
            </div>

            <div className="space-y-4 pt-4">
              <div className={`flex items-center justify-between p-5 rounded-3xl border transition-all duration-700 ${syncStep >= 1 ? 'bg-indigo-500/10 border-indigo-500/30' : 'bg-slate-900/50 border-slate-800'}`}>
                <div className="flex items-center gap-4">
                  <div className={`w-10 h-10 rounded-xl flex items-center justify-center ${syncStep >= 1 ? 'bg-indigo-500 text-white shadow-lg' : 'bg-slate-800 text-slate-500'}`}>
                    <Users size={20} />
                  </div>
                  <div className="text-left">
                    <p className={`text-sm font-black ${syncStep >= 1 ? 'text-white' : 'text-slate-500'}`}>Subscriber Sync</p>
                    <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">Entering Follow-Back Loop</p>
                  </div>
                </div>
                {syncStep >= 1 && <CheckCircle size={20} className="text-emerald-500 animate-in zoom-in" />}
              </div>

              <div className={`flex items-center justify-between p-5 rounded-3xl border transition-all duration-700 ${syncStep >= 2 ? 'bg-purple-500/10 border-purple-500/30' : 'bg-slate-900/50 border-slate-800'}`}>
                <div className="flex items-center gap-4">
                  <div className={`w-10 h-10 rounded-xl flex items-center justify-center ${syncStep >= 2 ? 'bg-purple-500 text-white shadow-lg' : 'bg-slate-800 text-slate-500'}`}>
                    <RefreshCcw size={20} className={syncStep === 1 ? "animate-spin" : ""} />
                  </div>
                  <div className="text-left">
                    <p className={`text-sm font-black ${syncStep >= 2 ? 'text-white' : 'text-slate-500'}`}>Elite Verification</p>
                    <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">Badge Distribution Active</p>
                  </div>
                </div>
                {syncStep >= 2 && <CheckCircle size={20} className="text-emerald-500 animate-in zoom-in" />}
              </div>
            </div>

            <p className="text-[10px] font-black text-slate-600 uppercase tracking-[0.2em]">Wetaract Engine: Initializing Ecosystem...</p>
          </div>
        </div>
      )}

      <Layout activeView={activeView} setActiveView={setActiveView} user={user}>
        {renderView()}
      </Layout>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import Auth from './views/Auth';
import Dashboard from './views/Dashboard';
import Community from './views/Community';
import Campaigns from './views/Campaigns';
import Membership from './views/Membership';
import Profile from './views/Profile';
import Referrals from './views/Referrals';
import WalletView from './views/Wallet';
import { MembershipStatus, SocialPlatform, UserProfile } from './types';
import { 
  Sparkles, 
  RefreshCcw, 
  ArrowLeftRight, 
  Users, 
  CheckCircle,
  Instagram,
  Facebook,
  Twitter,
  Youtube,
  Music2,
  Zap,
  Target,
  Link as LinkIcon,
  MessageSquare,
  Globe,
  Coins,
  Cpu,
  Info,
  Play
} from 'lucide-react';

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [activeView, setActiveView] = useState('dashboard');
  const [isSyncing, setIsSyncing] = useState(false);
  const [syncStep, setSyncStep] = useState(0);
  const [isLoading, setIsLoading] = useState(true);

  const [user, setUser] = useState<UserProfile | null>(null);

  // Initial Data Fetch from Laravel
  useEffect(() => {
    if (isAuthenticated) {
      fetch('/api/v1/user')
        .then(res => res.json())
        .then(data => {
          setUser(data);
          setIsLoading(false);
        })
        .catch(err => console.error("API Load Error", err));
    }
  }, [isAuthenticated]);

  const handleMembershipUpgrade = async (planId: string) => {
    if (!user) return;

    setIsSyncing(true);
    setSyncStep(1);

    try {
      const response = await fetch('/api/v1/membership/upgrade', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' }
      });

      if (!response.ok) {
        const err = await response.json();
        alert(err.error || "Upgrade failed");
        setIsSyncing(false);
        return;
      }

      const result = await response.json();
      setSyncStep(2);

      setTimeout(() => {
        setUser(result.user);
        setIsSyncing(false);
        setActiveView('dashboard');
      }, 2000);
    } catch (error) {
      alert("Connectivity error. Please try again.");
      setIsSyncing(false);
    }
  };

  const handleUpdateUser = (updatedUser: UserProfile) => {
    setUser(updatedUser);
  };

  if (!isAuthenticated) {
    return <Auth onLoginSuccess={() => setIsAuthenticated(true)} />;
  }

  if (isLoading || !user) {
    return (
      <div className="min-h-screen bg-slate-950 flex items-center justify-center">
        <div className="animate-spin rounded-full h-12 w-12 border-t-2 border-indigo-500"></div>
      </div>
    );
  }

  const renderView = () => {
    switch (activeView) {
      case 'dashboard': return <Dashboard user={user} />;
      case 'community': return <Community currentUser={user} />;
      case 'campaigns': return <Campaigns currentUserInterests={user.interests} />;
      case 'wallet': return <WalletView user={user} onUpdateUser={handleUpdateUser} />;
      case 'referrals': return <Referrals user={user} />;
      case 'profile': return <Profile user={user} onUpdateUser={handleUpdateUser} />;
      case 'premium': return <Membership onUpgrade={handleMembershipUpgrade} currentStatus={user.membershipStatus} user={user} />;
      default: return <Dashboard user={user} />;
    }
  };

  return (
    <div className="relative min-h-screen bg-slate-950">
      {isSyncing && (
        <div className="fixed inset-0 z-[100] bg-slate-950/95 backdrop-blur-xl flex items-center justify-center p-6">
          <div className="max-w-lg w-full glass p-10 rounded-[3rem] text-center space-y-8 animate-in zoom-in duration-500 border-indigo-500/30">
            <div className="relative w-32 h-32 mx-auto mb-8">
              <div className="absolute inset-0 bg-indigo-500/20 rounded-full animate-ping"></div>
              <div className="relative z-10 w-full h-full bg-indigo-600 rounded-[2.5rem] flex items-center justify-center neo-shadow">
                <ArrowLeftRight size={48} className="text-white" />
              </div>
            </div>
            <h2 className="text-4xl font-black text-white tracking-tight">Syncing with MySQL Hub</h2>
            <p className="text-slate-400 font-medium">Validating your transaction and updating your global profile...</p>
          </div>
        </div>
      )}

      <Layout activeView={activeView} setActiveView={setActiveView} user={user}>
        {renderView()}
      </Layout>
    </div>
  );
};

export default App;
